  ('disabled-0a2fc18c-moex-00080', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-113-6948958a', 'sub-disabled-0a2fc18c-07', NULL, 'single_choice', '海鮮煎餅的市場需求函數為：Q = 2,400–20P。若是目前海鮮煎餅的售價 D 為一份80元，則海鮮煎餅此時的需求之價格彈性為：', '["完全彈性（perfectlyelastic）", "富有彈性（elastic）", "單位彈性（unitaryelastic）", "缺乏彈性（inelastic）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:25+00:00", "source_pdf_sha1": "85be7467d750", "answer_pdf_sha1": "6fb4e390116a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "408", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
